import pytest
from typing import List

def max_subarray_sum(arr: List[int]) -> int:
    """
    Finds the maximum sum of a contiguous subarray within a given array.

    Args:
        arr: A list of integers.

    Returns:
        The maximum sum of a contiguous subarray.  Returns 0 if the input array is empty.
    """
    if not arr:
        return 0
    max_sum = current = arr[0]
    for num in arr[1:]:
        current = max(num, current + num)
        max_sum = max(max_sum, current)
    return max_sum


class TestMaxSubarraySum:
    def test_empty_array(self):
        assert max_subarray_sum([]) == 0

    def test_single_element_array(self):
        assert max_subarray_sum([5]) == 5
        assert max_subarray_sum([-3]) == -3

    def test_all_positive_numbers(self):
        assert max_subarray_sum([1, 2, 3, 4, 5]) == 15

    def test_all_negative_numbers(self):
        assert max_subarray_sum([-1, -2, -3, -4, -5]) == -1

    def test_mixed_positive_and_negative_numbers(self):
        assert max_subarray_sum([-2, 1, -3, 4, -1, 2, 1, -5, 4]) == 6
        assert max_subarray_sum([1, -2, 3, -4, 5]) == 5
        assert max_subarray_sum([-1, 0, -2]) == 0
        assert max_subarray_sum([-2, -3, 4, -1, -2, 1, 5, -3]) == 7

    def test_array_with_zeroes(self):
        assert max_subarray_sum([0, 0, 0, 0]) == 0
        assert max_subarray_sum([-1, 0, 1, -2]) == 1
        assert max_subarray_sum([-1, 0, -2]) == 0

    def test_large_numbers(self):
        assert max_subarray_sum([1000, -500, 2000]) == 2500

    def test_array_with_only_one_positive_number(self):
        assert max_subarray_sum([-10, -20, 5, -30]) == 5

    def test_array_starting_with_negative_numbers(self):
        assert max_subarray_sum([-1, 2, 3, -4, 5]) == 6

    def test_array_ending_with_negative_numbers(self):
        assert max_subarray_sum([5, -4, 3, 2, -1]) == 6

    def test_long_array(self):
        long_array = list(range(-100, 101))
        assert max_subarray_sum(long_array) == 5050

    def test_array_with_repeating_numbers(self):
        assert max_subarray_sum([1, 1, 1, 1, 1]) == 5
        assert max_subarray_sum([-1, -1, -1, -1, -1]) == -1
        assert max_subarray_sum([1, -1, 1, -1, 1]) == 1
